end

function LxEvent:Destroy()
    local eventList = self._eventList
    if (eventList) then
        for k,funcList in pairs(eventList) do
            for m,func in pairs(funcList) do
                funcList[m] = nil
            end
            eventList[k] = nil
        end
        self._eventList = nil
    end
    self._eventRunList = nil
end

function LxEvent:EventAdd(event, func)
    local typeEvent = event and type(event) or nil
    if typeEvent ~= "string" then
        error("event != string | " .. tostring(typeEvent))
    end

    local typeFunc = func and type(func) or nil
    if typeFunc ~= "function" then
        error("handler != function, " .. tostring(typeFunc))
    end

    local eventList = self._eventList
    local funcList = eventList[event]
    if not funcList then
        funcList = {}
        eventList[event] = funcList
    end
    table.insert(funcList, func)
end

function LxEvent:EventSend(event, ...)
    local eventList = self._eventList
    local funcList = eventList[event]
    if (not funcList) then
        return
    end

    --正在执行的事件 产生的结果不在响应同样的事件
    if self._eventRunList[event] then
        if LOG_INFO_ENABLED then
            print("event is infinite Loop calling, please check the code, event = "..tostring(event))
        end
        return
    end

    --列表反转之后执行，避免事件中进行了删除事件
    local tmpList = table.reverse(funcList)
    self._eventRunList[event] = tmpList

    while #tmpList > 0 do
        local v = table.remove(tmpList)
        LXFW.xpcall(v, ...)
    end

    if self._eventRunList then
        self._eventRunList[event] = nil
    end
end

function LxEvent:EventRemove(event, listener)
    local eventList = self._eventList
    local funcList = eventList[event]
    if not funcList then return end
    for k, v in ipairs(funcList) do
        if listener == v then
            table.remove(funcList, k)
            break
        end
    end

    if not self._eventRunList then
        return
    end
    ---删除正在执行事件中列表对应的函数
    local runFunList = self._eventRunList[event]
    if(runFunList) then
        for k, v in ipairs(runFunList) do
            if listener == v then
                table.remove(runFunList, k)
                break
            end
        end
    end
